  1	import type { FC } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
  4	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
  5	import PlanCutoverMigrationModal from 'src/plans/actions/components/CutoverModal/PlanCutoverMigrationModal';
  6	
  7	import { ConsoleTimestamp } from '@components/ConsoleTimestamp/ConsoleTimestamp';
  8	import { useDrawer } from '@components/DrawerContext/useDrawer';
  9	import HelpText from '@components/HelpText';
 10	import type { V1beta1Plan, V1beta1PlanStatusMigrationVms } from '@kubev2v/types';
 11	import {
 12	  Alert,
 13	  Button,
 14	  ButtonVariant,
 15	  Split,
 16	  SplitItem,
 17	  Stack,
 18	  StackItem,
 19	} from '@patternfly/react-core';
 20	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 21	import { taskStatuses } from '@utils/constants';
 22	import { VirtualMachineModelGroupVersionKind } from '@utils/crds/common/models';
 23	import { isEmpty } from '@utils/helpers';
 24	import { useForkliftTranslation } from '@utils/i18n';
 25	
 26	import { CUTOVER_NAME, VIRTUAL_MACHINE_CREATION_NAME } from '../../../../utils/utils';
 27	import { getPipelineProgressIcon } from '../../../utils/icon';
 28	import { getPipelineTasks } from '../../../utils/utils';
 29	import PipelineTasksDrawer from '../PipelineTasksDrawer';
 30	
 31	import './MigrationProgressTable.scss';
 32	
 33	type MigrationProgressTableProps = {
 34	  plan: V1beta1Plan;
 35	  statusVM: V1beta1PlanStatusMigrationVms | undefined;
 36	  vmCreated?: boolean;
 37	  vmName?: string;
 38	  targetNamespace?: string;
 39	};
 40	
 41	const MigrationProgressTable: FC<MigrationProgressTableProps> = ({
 42	  plan,
 43	  statusVM,
 44	  targetNamespace,
 45	  vmCreated,
 46	  vmName,
 47	}) => {
 48	  const { t } = useForkliftTranslation();
 49	  const { openDrawer } = useDrawer();
 50	  const { showModal } = useModal();
 51	  const navigate = useNavigate();
 52	  const pipeline = statusVM?.pipeline ?? [];
 53	
 54	  return (
 55	    <Table>
 56	      <Thead>
 57	        <Tr>
 58	          <Th>{t('Name')}</Th>
 59	          <Th>{t('Description')}</Th>
 60	          <Th>{t('Completed at')}</Th>
 61	        </Tr>
 62	      </Thead>
 63	      <Tbody>
 64	        {(pipeline ?? []).map((pipe) => {
 65	          const isVMCreatedAndVMCreationPipeline =
 66	            pipe?.name === VIRTUAL_MACHINE_CREATION_NAME && vmCreated;
 67	          const isCutoverPipeline = pipe?.name === CUTOVER_NAME;
 68	          const isTasksEmpty = isEmpty(pipe?.tasks);
 69	
 70	          return (
 71	            <Tr key={pipe?.name}>
 72	              <Td modifier="nowrap">
 73	                <Split hasGutter>
 74	                  <SplitItem>{getPipelineProgressIcon(pipe)}</SplitItem>
 75	                  <SplitItem>{pipe?.name}</SplitItem>
 76	                </Split>
 77	              </Td>
 78	              <Td>
 79	                {!isVMCreatedAndVMCreationPipeline && isTasksEmpty && pipe?.description}
 80	                {!isTasksEmpty && !isCutoverPipeline && (
 81	                  <>
 82	                    {t('Completed ')}
 83	                    <Button
 84	                      variant={ButtonVariant.link}
 85	                      onClick={() => {
 86	                        openDrawer(
 87	                          <PipelineTasksDrawer name={pipe?.name} tasks={pipe.tasks} />,
 88	                          <h3>
 89	                            {pipe?.name}
 90	                            <HelpText>{vmName}</HelpText>
 91	                          </h3>,
 92	                        );
 93	                      }}
 94	                      isInline
 95	                    >
 96	                      {t('{{completed}} of {{total}} {{name}}', getPipelineTasks(pipe))}
 97	                    </Button>
 98	                    {t(' tasks')}
 99	                  </>
100	                )}
101	                {isVMCreatedAndVMCreationPipeline && (
102	                  <>
103	                    {t('Created ')}
104	                    <Button
105	                      variant={ButtonVariant.link}
106	                      onClick={() => {
107	                        navigate(
108	                          getResourceUrl({
109	                            groupVersionKind: VirtualMachineModelGroupVersionKind,
110	                            name: vmName,
111	                            namespace: targetNamespace,
112	                          }),
113	                        );
114	                      }}
115	                      isInline
116	                    >
117	                      {vmName}
118	                    </Button>
119	                  </>
120	                )}
121	                {isCutoverPipeline && pipe?.phase === taskStatuses.completed && (
122	                  <>{pipe?.description}</>
123	                )}
124	                {isCutoverPipeline && pipe?.phase !== taskStatuses.completed && (
125	                  <Stack>
126	                    <StackItem>{t('Paused')}</StackItem>
127	                    <StackItem>
128	                      <Button
129	                        onClick={() => {
130	                          showModal(<PlanCutoverMigrationModal plan={plan} />);
131	                        }}
132	                        variant={ButtonVariant.link}
133	                        className="forklift-progress-table__schedule-cutover"
134	                      >
135	                        {t('Schedule cutover')}
136	                      </Button>
137	                    </StackItem>
138	                  </Stack>
139	                )}
140	                {pipe?.error?.reasons && !isEmpty(pipe?.error?.reasons) && (
141	                  <div className="pf-v6-u-mt-sm">
142	                    <Alert variant="danger" title={t('Error details')} isInline isPlain>
143	                      <ul>
144	                        {pipe.error.reasons.map((reason: string, idx: number) => (
145	                          <li key={idx}>{reason}</li>
146	                        ))}
147	                      </ul>
148	                    </Alert>
149	                  </div>
150	                )}
151	              </Td>
152	              <Td>
153	                <ConsoleTimestamp timestamp={pipe?.completed ?? null} showGlobalIcon={false} />
154	              </Td>
155	            </Tr>
156	          );
157	        })}
158	      </Tbody>
159	    </Table>
160	  );
161	};
162	
163	export default MigrationProgressTable;

